mapper.select:
SELECT id, report_code, user_account, role_type,
       create_by, create_time, update_by, update_time
FROM tb_report_user_role
WHERE report_code = #{reportCode}
  AND user_account = #{userAccount}

mapper.update:
UPDATE tb_report_user_role
SET role_type = #{roleType},
    update_by = #{updateBy},
    update_time = NOW()
WHERE report_code = #{reportCode}
  AND user_account = #{userAccount}

mapper.delete:
DELETE FROM tb_report_user_role
WHERE report_code = #{reportCode}
  AND user_account = #{userAccount}

